window.ventasAddonOpenId = null;


function cerrarAddonDetail() {
    window.ventasAddonOpenId = null;

    const panel = document.getElementById("ventasAddonDetail");
    const body = document.getElementById("ventasAddonDetailBody");
    const subtitle = document.getElementById("ventasAddonDetailSubtitle");

    if (panel) panel.style.display = "none";
    if (body) body.innerHTML = "";
    if (subtitle) subtitle.textContent = "";

    if (ventasGridApi) {
        ventasGridApi.refreshCells({ force: true, columns: ["addons_toggle"] });
    }
}

async function abrirAddonDetail(idventa) {
    window.ventasAddonOpenId = idventa;

    const panel = document.getElementById("ventasAddonDetail");
    const body = document.getElementById("ventasAddonDetailBody");
    const subtitle = document.getElementById("ventasAddonDetailSubtitle");

    if (panel) panel.style.display = "block";
    if (body) body.innerHTML = '<div class="ventas-addon-loading">Cargando addons...</div>';
    if (subtitle) subtitle.textContent = "Venta #" + idventa;

    if (ventasGridApi) {
        ventasGridApi.refreshCells({ force: true, columns: ["addons_toggle"] });
    }

    try {
        const resp = await fetch("ventas_addons_detail.php?idventa=" + encodeURIComponent(idventa), {
            method: "GET",
            cache: "no-store"
        });

        const txt = await resp.text();
        let data = [];

        try {
            data = JSON.parse(txt);
        } catch (e) {
            if (body) body.innerHTML = "<div>Error al interpretar respuesta.</div>";
            return;
        }

        renderAddonDetail(data, idventa);
    } catch (e) {
        if (body) body.innerHTML = "<div>Error al cargar addons.</div>";
    }
}

function renderAddonDetail(data, idventa) {
    const body = document.getElementById("ventasAddonDetailBody");
    const subtitle = document.getElementById("ventasAddonDetailSubtitle");

    if (subtitle) subtitle.textContent = "Venta #" + idventa;

    if (!body) return;

    if (!Array.isArray(data) || !data.length) {
        body.innerHTML = "<div>No hay addons para esta venta.</div>";
        return;
    }

    let html = `
        <table class="ventas-addon-table">
            <thead>
                <tr>
                    <th>Addon</th>
                    <th>Fecha activación</th>
                    <th>Precio</th>
                    <th>Verificación realizada</th>
                </tr>
            </thead>
            <tbody>
    `;

    data.forEach(function(r) {
        html += `
            <tr>
                <td>${r.addon || ""}</td>
                <td>${r.fecha_activacion || ""}</td>
                <td>${r.precio || ""}</td>
                <td>${r.verificacion_realizada || ""}</td>
            </tr>
        `;
    });

    html += `
            </tbody>
        </table>
    `;

    body.innerHTML = html;
}

