    margin: 12px;
    border: 1px solid #dfe5ec;
    border-radius: 12px;
    background: #fff;
    box-shadow: 0 10px 30px rgba(16,24,40,.08);
    overflow: hidden;
}

.ventas-addon-detail-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 12px;
    padding: 14px 16px;
    border-bottom: 1px solid #eceff3;
    background: #fafbfd;
}

.ventas-addon-detail-title {
    font-size: 18px;
    font-weight: 700;
    color: #c2410c;
}

.ventas-addon-detail-subtitle {
    font-size: 13px;
    color: #64748b;
    margin-top: 3px;
}

.ventas-addon-detail-body {
    padding: 14px 16px 18px;
}

.ventas-addon-loading {
    color: #475569;
    font-size: 13px;
    font-weight: 600;
}

.ventas-addon-table {
    width: 100%;
    border-collapse: collapse;
    font-size: 13px;
}

.ventas-addon-table th,
.ventas-addon-table td {
    border: 1px solid #e5e7eb;
    padding: 10px 12px;
    text-align: left;
}

.ventas-addon-table th {
    background: #f8fafc;
    color: #334155;
    font-weight: 700;
}

.ventas-addon-table td {
    background: #fff;
    color: #111827;
}
